const aggregated = $input.first();
const allBinaries = aggregated.binary || {};
const binaryKeys = Object.keys(allBinaries);
if (binaryKeys.length === 0) throw new Error('No binary data found after aggregation.');
return [{
  json: { attachmentNames: binaryKeys.join(','), attachmentCount: binaryKeys.length },
  binary: allBinaries
}];

