const cfg  = $('Set Context').item.json;
const mail = $('Zoho Mail Trigger').item.json;
const ai   = $('AI Agent').item.json.output;

const priorityEmoji = { 'High': '🔴', 'Medium': '🟡', 'Low': '🟢' };
const emoji     = priorityEmoji[ai.priority] || '🟡';
const badgeCss  = ai.priority === 'High' ? 'badge-high' : (ai.priority === 'Low' ? 'badge-low' : 'badge-mid');
const keyNums   = (ai.key_numbers || []).join(', ') || null;

const aiRows = [
  `<p><span class="lbl">Type:</span> ${ai.type}</p>`,
  `<p><span class="lbl">Priority:</span> <span class="badge ${badgeCss}">${emoji} ${ai.priority}</span></p>`,
  `<p><span class="lbl">Summary:</span> ${ai.summary}</p>`,
  ai.deadline        ? `<p><span class="lbl">⏰ Deadline:</span> <strong>${ai.deadline}</strong></p>` : '',
  ai.action_required ? `<p><span class="lbl">✅ Action Required:</span> ${ai.action_required}</p>` : '',
  keyNums            ? `<p><span class="lbl">🔢 Key Numbers:</span> ${keyNums}</p>` : ''
].filter(Boolean).join('\n');

const html = `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8">
<style>
  body{font-family:'Segoe UI',sans-serif;background:#f9fafb;margin:0;padding:40px;color:#1f2937}
  .wrap{background:#fff;border-radius:12px;box-shadow:0 6px 20px rgba(0,0,0,.08);padding:30px;max-width:900px;margin:auto}
  .ai-box{background:#eff6ff;border-left:4px solid #3b82f6;border-radius:8px;padding:16px 20px;margin-bottom:24px}
  .ai-box h3{margin:0 0 12px;font-size:15px;color:#1d4ed8}
  .ai-box p{margin:4px 0;font-size:14px;color:#1e40af}
  .lbl{font-weight:600;display:inline-block;width:110px}
  .badge{display:inline-block;padding:2px 10px;border-radius:12px;font-size:12px;font-weight:700}
  .badge-high{background:#fee2e2;color:#b91c1c}
  .badge-mid{background:#fef3c7;color:#92400e}
  .badge-low{background:#d1fae5;color:#065f46}
  .hdr{border-bottom:1px solid #e5e7eb;margin-bottom:20px;padding-bottom:15px}
  .hdr p{margin:4px 0;font-size:14px}
  .hdr span{font-weight:600;color:#111827}
  .body-lbl{font-size:15px;font-weight:600;color:#2563eb;margin-bottom:10px}
  .body-cnt{padding:15px;background:#f3f4f6;border-radius:8px;font-size:14px;line-height:1.7}
  .footer{margin-top:20px;font-size:12px;color:#9ca3af;border-top:1px solid #e5e7eb;padding-top:12px}
</style></head>
<body><div class="wrap">
  <div class="ai-box"><h3>🤖 AI Analysis</h3>${aiRows}</div>
  <div class="hdr">
    <p><span>From:</span> ${mail.fromAddress}</p>
    <p><span>To:</span> ${mail.toAddress}</p>
    <p><span>Received At:</span> ${new Date(mail.receivedTime).toLocaleString('en-US',{timeZone:'Asia/Ho_Chi_Minh'})}</p>
  </div>
  <div class="body-lbl">Original Content</div>
  <div class="body-cnt">${mail.html || mail.summary || '(No content available)'}</div>
  <div class="footer">${cfg.footer_note}</div>
</div></body></html>`;

return [{
  json: {
    emailHtml:         html,
    emailSubject:      `${cfg.subject_prefix} ${emoji} [${ai.type}] ${mail.subject}`,
    ai_priority:       ai.priority,
    ai_priority_emoji: emoji,
    ai_type:           ai.type,
    ai_summary:        ai.summary,
    ai_deadline:       ai.deadline || null,
    ai_action:         ai.action_required || null,
    ai_key_numbers:    keyNums
  }
}];
